# Geometry types module - defines interfaces and enums for geometric shapes
from math_utils import Point2D

interface IShape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

interface IMeasurable:
    @abstract
    def measure(self) -> tuple[float, str]:
        ...

enum ShapeType:
    CIRCLE = 1
    RECTANGLE = 2
    TRIANGLE = 3
    POLYGON = 4

