# Math utilities module - provides structs and helper functions

struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point2D) -> float:
        d_x: float = self.x - other.x
        d_y: float = self.y - other.y
        return (d_x * d_x + d_y * d_y) ** 0.5

    def to_string(self) -> str:
        return f"({self.x}, {self.y})"

@static
class GeometryUtils:
    PI: float = 3.14159

    @staticmethod
    def degrees_to_radians(degrees: float) -> float:
        return degrees * GeometryUtils.PI / 180.0

    @staticmethod
    def calculate_average(numbers: list[float]) -> float:
        total: float = 0.0
        for n in numbers:
            total += n
        return total / len(numbers)

