# Shapes module - implements classes using types from geometry_types and math_utils
from geometry_types import IShape, IMeasurable, ShapeType
from math_utils import Point2D, GeometryUtils

@abstract
class ShapeBase:
    _shape_id: int
    _shape_type: ShapeType

    def __init__(self, shape_id: int, shape_type: ShapeType):
        self._shape_id = shape_id
        self._shape_type = shape_type

    def get_id(self) -> int:
        return self._shape_id

    def get_type(self) -> ShapeType:
        return self._shape_type

    @virtual
    def describe(self) -> str:
        return f"Shape #{self._shape_id}"

class Circle(ShapeBase, IShape, IMeasurable):
    center: Point2D
    radius: float

    def __init__(self, shape_id: int, center: Point2D, radius: float):
        super().__init__(shape_id, ShapeType.CIRCLE)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        r_squared: float = self.radius * self.radius
        return GeometryUtils.PI * r_squared

    @override
    def perimeter(self) -> float:
        return 2.0 * GeometryUtils.PI * self.radius

    @override
    def describe(self) -> str:
        return f"Circle {self.radius} at {self.center.to_string()}"

    @override
    def measure(self) -> tuple[float, str]:
        return (self.area(), "square units")

class Rectangle(ShapeBase, IShape, IMeasurable):
    top_left: Point2D
    width: float
    height: float

    def __init__(self, shape_id: int, top_left: Point2D, width: float, height: float):
        super().__init__(shape_id, ShapeType.RECTANGLE)
        self.top_left = top_left
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width}x{self.height} at {self.top_left.to_string()}"

    @override
    def measure(self) -> tuple[float, str]:
        perimeter: float = self.perimeter()
        return (perimeter, "linear units")
